```javascript
const PAGE_SIZE = 4096;
const PAGE_SHIFT = 12;
const PAGE_MASK = PAGE_SIZE - 1;

class Memory {
    constructor() {
        this.pages = new Map(); // page number -> Buffer(PAGE_SIZE)
    }

    getPage(pageNum) {
        let page = this.pages.get(pageNum);
        if (!page) {
            page = Buffer.alloc(PAGE_SIZE, 0);
            this.pages.set(pageNum, page);
        }
        return page;
    }

    read8(addr) {
        const pageNum = addr >>> PAGE_SHIFT;
        const offset = addr & PAGE_MASK;
        return this.getPage(pageNum)[offset];
    }

    write8(addr, val) {
        const pageNum = addr >>> PAGE_SHIFT;
        const offset = addr & PAGE_MASK;
        this.getPage(pageNum)[offset] = val;
    }

    read32(addr) {
        // Handle page boundary crossing
        const pageNum = addr >>> PAGE_SHIFT;
        const offset = addr & PAGE_MASK;
        if (offset <= PAGE_SIZE - 4) {
            return this.getPage(pageNum).readUInt32LE(offset);
        }
        // Cross page boundary
        return this.read8(addr) | (this.read8(addr+1) << 8) | (this.read8(addr+2) << 16) | (this.read8(addr+3) << 24);
    }

    write32(addr, val) {
        const pageNum = addr >>> PAGE_SHIFT;
        const offset = addr & PAGE_MASK;
        if (offset <= PAGE_SIZE - 4) {
            this.getPage(pageNum).writeUInt32LE(val, offset);
        } else {
            this.write8(addr, val & 0xFF);
            this.write8(addr+1, (val >>> 8) & 0xFF);
            this.write8(addr+2, (val >>> 16) & 0xFF);
            this.write8(addr+3, (val >>> 24) & 0xFF);
        }
    }

    read16(addr) {
        return this.read8(addr) | (this.read8(addr+1) << 8);
    }

    write16(addr, val) {
        this.write8(addr, val & 0xFF);
        this.write8(addr+1, (val >>> 8) & 0xFF);
    }

    // Copy from Node.js Buffer into memory
    loadBuffer(addr, buf) {
        for (let i = 0; i < buf.length; i++) {
            this.write8(addr + i, buf[i]);
        }
    }
}
```

